/*
  Seed ALL provider trade exam answer keys (14 trades x 20 questions).
  Table: dbo.IndorProveedorExamPreguntas
    - CorrectIndex is ZERO-BASED (0 = first option in OptionsJson).
    - Use vw_IndorProveedorExamAnswerKey to read the correct answer text.

  Prerequisite: CreateProviderPortalTables.sql (creates IndorProveedorExamPreguntas
  and IndorProveedorExamRespuestas for storing each provider''s submitted answers).

  Trades: electrical, plumbing, hvac, handyman, construction, bathroom, kitchen,
          roofing, painting, flooring, cleaning, landscaping, pest, appliance
*/
SET NOCOUNT ON;
GO

IF OBJECT_ID(N'dbo.IndorProveedorExamPreguntas', N'U') IS NULL
BEGIN
    RAISERROR('Run CreateProviderPortalTables.sql first.', 16, 1);
    RETURN;
END
GO

DELETE FROM dbo.IndorProveedorExamPreguntas;
GO

GO

-- Human-readable answer key (correct option text per question)
IF OBJECT_ID(N'dbo.vw_IndorProveedorExamAnswerKey', N'V') IS NOT NULL
    DROP VIEW dbo.vw_IndorProveedorExamAnswerKey;
GO

CREATE VIEW dbo.vw_IndorProveedorExamAnswerKey
AS
SELECT
    p.TradeCode,
    p.QuestionNumber,
    p.PageNumber,
    p.TextEn AS QuestionText,
    p.CorrectIndex,
    CASE p.CorrectIndex
        WHEN 0 THEN JSON_VALUE(p.OptionsJson, '$[0]')
        WHEN 1 THEN JSON_VALUE(p.OptionsJson, '$[1]')
        WHEN 2 THEN JSON_VALUE(p.OptionsJson, '$[2]')
        WHEN 3 THEN JSON_VALUE(p.OptionsJson, '$[3]')
    END AS CorrectAnswerText,
    p.OptionsJson,
    p.Activo
FROM dbo.IndorProveedorExamPreguntas p;
GO

DECLARE @QuestionCount INT = (SELECT COUNT(*) FROM dbo.IndorProveedorExamPreguntas);
DECLARE @TradeCount INT = (SELECT COUNT(DISTINCT TradeCode) FROM dbo.IndorProveedorExamPreguntas);
PRINT CONCAT('Seeded ', @QuestionCount, ' exam questions across ', @TradeCount, ' trades.');
GO

-- Quick verification: list answer key summary by trade
SELECT TradeCode, COUNT(*) AS QuestionCount,
       MIN(CorrectIndex) AS MinCorrectIndex, MAX(CorrectIndex) AS MaxCorrectIndex
FROM dbo.IndorProveedorExamPreguntas
GROUP BY TradeCode
ORDER BY TradeCode;
GO
